        {
          id: "m1-chapter-2-autonomous-db-serverless",
          title: "Chapter 2: Autonomous Database Serverless",
          description: "Autonomous Database Serverless MCQ Preparation",
          questions: [
            { id: 1, question: "What is the primary advantage of provisioning an Autonomous Database Serverless instance?", options: [{ id: "A", text: "It requires manual hardware configuration before use." }, { id: "B", text: "It allows users to quickly deploy a database without managing the underlying infrastructure." }, { id: "C", text: "It permanently allocates maximum compute resources." }, { id: "D", text: "It eliminates the need for database users." }], correctAnswer: "B", explanation: "Serverless provisioning automates infrastructure setup, allowing databases to be created quickly. Users can focus on application development instead of managing servers and hardware." },
            { id: 2, question: "Why is autoscaling an important feature of Autonomous Database Serverless?", options: [{ id: "A", text: "It automatically changes the database schema." }, { id: "B", text: "It adjusts compute resources based on workload demand, helping optimize performance and cost." }, { id: "C", text: "It creates additional database users during peak usage." }, { id: "D", text: "It automatically backs up the database every hour." }], correctAnswer: "B", explanation: "Autoscaling increases or decreases compute resources as workload changes. This maintains performance during peak demand while reducing costs during low usage." },
            { id: 3, question: "What is the main purpose of managing users in elastic pools?", options: [{ id: "A", text: "To control authentication, authorization, and efficient resource sharing among multiple databases." }, { id: "B", text: "To increase the database storage capacity." }, { id: "C", text: "To disable autoscaling during maintenance." }, { id: "D", text: "To create network security rules." }], correctAnswer: "A", explanation: "User management ensures only authorized users can access resources with appropriate privileges. Elastic pools also enable multiple databases to share resources efficiently." },
            { id: 4, question: "Why should database administrators regularly monitor an Autonomous Database?", options: [{ id: "A", text: "To manually tune SQL queries every hour." }, { id: "B", text: "To identify performance trends, resource utilization, and potential issues before they affect users." }, { id: "C", text: "To reinstall the database software after every update." }, { id: "D", text: "To prevent the database from performing automatic backups." }], correctAnswer: "B", explanation: "Monitoring provides insights into database health, workload, and resource consumption. Early detection of issues helps maintain performance and availability." },
            { id: 5, question: "Which combination of features best reflects the operational goals of Autonomous Database Serverless?", options: [{ id: "A", text: "Manual resource allocation and fixed capacity." }, { id: "B", text: "Automatic provisioning, elastic scaling, and simplified database management." }, { id: "C", text: "Manual patching and dedicated hardware management." }, { id: "D", text: "Static compute allocation with user-managed maintenance." }], correctAnswer: "B", explanation: "Autonomous Database Serverless automates deployment, scaling, patching, and maintenance. This reduces administrative effort while improving efficiency and reliability. ----" },
            { id: 6, question: "What is a key advantage of scaling resources in Autonomous Database?", options: [{ id: "A", text: "Compute and storage must always be scaled together." }, { id: "B", text: "Compute (ECPU) and storage can be scaled independently." }, { id: "C", text: "Storage cannot be scaled after provisioning." }, { id: "D", text: "Scaling requires recreating the database." }], correctAnswer: "B", explanation: "Autonomous Database lets you adjust compute and storage separately. This provides flexibility to meet workload requirements without unnecessary resource allocation." },
            { id: 7, question: "What is the primary purpose of Compute Auto Scaling?", options: [{ id: "A", text: "To automatically increase storage capacity." }, { id: "B", text: "To increase compute resources when workload demand rises." }, { id: "C", text: "To automatically create standby databases." }, { id: "D", text: "To upgrade the database version." }], correctAnswer: "B", explanation: "Compute Auto Scaling automatically increases CPU resources during periods of high demand. This helps maintain application performance without manual intervention." },
            { id: 8, question: "How much can Compute Auto Scaling increase the allocated ECPUs?", options: [{ id: "A", text: "Up to twice the base ECPU allocation." }, { id: "B", text: "Up to three times the base ECPU allocation." }, { id: "C", text: "Unlimited scaling." }, { id: "D", text: "Only one additional ECPU." }], correctAnswer: "B", explanation: "When enabled, Compute Auto Scaling can temporarily increase compute capacity up to 3× the provisioned ECPU count to handle workload spikes." },
            { id: 9, question: "Which Autonomous Database deployment does NOT support Compute Auto Scaling?", options: [{ id: "A", text: "Dedicated Autonomous Database." }, { id: "B", text: "Paid Autonomous Database." }, { id: "C", text: "Always Free Autonomous Database." }, { id: "D", text: "Shared Autonomous Database." }], correctAnswer: "C", explanation: "Compute Auto Scaling is unavailable for Always Free databases. It is enabled by default for paid Autonomous Database deployments." },
            { id: 10, question: "What happens to database availability while a manual scaling operation is in progress?", options: [{ id: "A", text: "The database becomes unavailable." }, { id: "B", text: "Existing sessions are disconnected." }, { id: "C", text: "The database remains online and continues serving users." }, { id: "D", text: "The database switches to read-only mode." }], correctAnswer: "C", explanation: "Scaling is an online operation that does not interrupt database availability. Users can continue running workloads while scaling completes." },
            { id: 11, question: "Which lifecycle state indicates that a scaling operation is currently running?", options: [{ id: "A", text: "Updating" }, { id: "B", text: "Scaling in Progress" }, { id: "C", text: "Provisioning" }, { id: "D", text: "Pending" }], correctAnswer: "B", explanation: "During resource scaling, the database lifecycle state changes to Scaling in Progress. Once complete, it returns to Available." },
            { id: 12, question: "What happens after the scaling operation successfully completes?", options: [{ id: "A", text: "The database is restarted." }, { id: "B", text: "The lifecycle state changes to Available, and the new resource allocation becomes active." }, { id: "C", text: "Auto Scaling is disabled." }, { id: "D", text: "Existing connections must be re-established." }], correctAnswer: "B", explanation: "After scaling finishes, the database returns to the Available state. The updated compute or storage allocation is immediately usable." },
            { id: 13, question: "Why is independent scaling of compute and storage beneficial?", options: [{ id: "A", text: "It forces both resources to grow together." }, { id: "B", text: "It allows organizations to optimize costs by increasing only the required resource." }, { id: "C", text: "It prevents Auto Scaling from working." }, { id: "D", text: "It limits storage expansion." }], correctAnswer: "B", explanation: "Independent scaling avoids unnecessary resource increases. Organizations can add compute for performance or storage for capacity without affecting the other." },
            { id: 14, question: "If an Autonomous Database is provisioned with 6 ECPUs and Compute Auto Scaling is enabled, what is the maximum compute capacity it can temporarily reach?", options: [{ id: "A", text: "12 ECPUs" }, { id: "B", text: "18 ECPUs" }, { id: "C", text: "24 ECPUs" }, { id: "D", text: "Unlimited" }], correctAnswer: "B", explanation: "Auto Scaling allows the database to scale up to three times its base allocation. Therefore, a 6- ECPU database can temporarily reach 18 ECPUs." },
            { id: 15, question: "Which statement best describes Compute Auto Scaling in Autonomous Database?", options: [{ id: "A", text: "It requires scheduled downtime before activation." }, { id: "B", text: "It can be enabled or disabled dynamically without downtime." }, { id: "C", text: "It permanently changes the database size." }, { id: "D", text: "It is available only after manual approval." }], correctAnswer: "B", explanation: "Compute Auto Scaling settings can be changed at any time without stopping the database. This allows administrators to adapt resource policies with no service interruption. ----" },
            { id: 16, question: "What is the primary benefit of provisioning an Autonomous Database Serverless service?", options: [{ id: "A", text: "It requires manual database tuning and maintenance." }, { id: "B", text: "It automatically provisions a secure, highly available, and scalable database." }, { id: "C", text: "It requires users to configure backups before use." }, { id: "D", text: "It only provisions database storage." }], correctAnswer: "B", explanation: "Autonomous Database automates provisioning, security, scalability, and availability. This minimizes administrative effort while providing an enterprise-ready database." },
            { id: 17, question: "What happens in the background when an Autonomous Database Serverless instance is provisioned?", options: [{ id: "A", text: "A virtual machine is manually configured." }, { id: "B", text: "A 19c Pluggable Database (PDB) is created inside a Container Database (CDB)." }, { id: "C", text: "A dedicated operating system is installed." }, { id: "D", text: "A backup server is provisioned first." }], correctAnswer: "B", explanation: "Oracle provisions a 19c Pluggable Database (PDB) inside an existing Container Database (CDB). This follows Oracle's multitenant architecture." },
            { id: 18, question: "Which infrastructure components are automatically included with an Autonomous Database Serverless deployment?", options: [{ id: "A", text: "Manual backup scripts and local storage." }, { id: "B", text: "Exadata, RAC, encryption, and automatic backups." }, { id: "C", text: "Dedicated application servers." }, { id: "D", text: "External storage arrays." }], correctAnswer: "B", explanation: "Oracle automatically deploys the database on Exadata, Oracle RAC, with encryption and automatic backups already configured." },
            { id: 19, question: "Which resources must the administrator specify during provisioning?", options: [{ id: "A", text: "Tablespaces and initialization parameters." }, { id: "B", text: "Operating system version." }, { id: "C", text: "ECPU count and storage size." }, { id: "D", text: "RAC cluster configuration." }], correctAnswer: "C", explanation: "Users only choose the required compute (ECPUs) and storage capacity. Oracle manages all underlying infrastructure automatically." },
            { id: 20, question: "Which statement best describes the Display Name and Database Name?", options: [{ id: "A", text: "Both must always be identical." }, { id: "B", text: "Display Name is for identification, while Database Name is the database identifier and may be" }, { id: "C", text: "Database Name is generated after provisioning." }, { id: "D", text: "Display Name cannot be modified." }], correctAnswer: "B", explanation: "The Display Name helps users identify the database in the console. The Database Name is the actual database identifier and can be customized." },
            { id: 21, question: "Which configuration is enabled by default for paid Autonomous Database Serverless deployments?", options: [{ id: "A", text: "Manual backups." }, { id: "B", text: "Compute Auto Scaling." }, { id: "C", text: "Private networking only." }, { id: "D", text: "BYOL licensing." }], correctAnswer: "B", explanation: "Compute Auto Scaling is enabled by default for paid deployments. It is not enabled by default for Always Free databases." },
            { id: 22, question: "What is the purpose of Access Control Rules during provisioning?", options: [{ id: "A", text: "To increase database storage." }, { id: "B", text: "To restrict which IP addresses or CIDR blocks can connect to the database." }, { id: "C", text: "To configure automatic backups." }, { id: "D", text: "To manage database users." }], correctAnswer: "B", explanation: "Access Control Rules improve security by allowing only specified IP addresses or CIDR ranges to access the database." },
            { id: 23, question: "Which networking option is available when provisioning an Autonomous Database?", options: [{ id: "A", text: "Public access only." }, { id: "B", text: "Private subnet only." }, { id: "C", text: "Either a public endpoint or a private subnet deployment." }, { id: "D", text: "VPN access only." }], correctAnswer: "C", explanation: "The database can be deployed with either a publicly accessible endpoint or within a private subnet, depending on security requirements." },
            { id: 24, question: "Which licensing models are supported during provisioning?", options: [{ id: "A", text: "Open Source License and Enterprise License." }, { id: "B", text: "Bring Your Own License (BYOL) and License Included." }, { id: "C", text: "Subscription License only." }, { id: "D", text: "Trial License only." }], correctAnswer: "B", explanation: "Oracle allows customers to either use existing Oracle licenses (BYOL) or pay through the License Included model." },
            { id: 25, question: "Which statement best describes the Autonomous Database after provisioning is complete?", options: [{ id: "A", text: "Additional manual configuration is required before use." }, { id: "B", text: "The database enters the Available state and is immediately ready for connections." }, { id: "C", text: "Backups must be configured manually." }, { id: "D", text: "Users must first create tablespaces before connecting." }], correctAnswer: "B", explanation: "After provisioning completes, the database status changes from Provisioning to Available, and it is immediately ready for use." },
            { id: 26, question: "Why doesn't Autonomous Database require users to configure tablespaces, file systems, or initialization parameters?", options: [{ id: "A", text: "Because these tasks are automated by Oracle." }, { id: "B", text: "Because the database does not support them." }, { id: "C", text: "Because they are configured after deployment." }, { id: "D", text: "Because they are managed by users only." }], correctAnswer: "A", explanation: "Oracle automates traditional DBA tasks, allowing users to focus on applications rather than infrastructure management." },
            { id: 27, question: "Which feature contributes most to the \"self-managing\" capability of Autonomous Database?", options: [{ id: "A", text: "Automatic provisioning, patching, backups, and resource management." }, { id: "B", text: "Manual SQL tuning." }, { id: "C", text: "User-managed storage allocation." }, { id: "D", text: "Manual operating system updates." }], correctAnswer: "A", explanation: "Autonomous Database automates provisioning, maintenance, patching, scaling, and backups, significantly reducing administrative overhead. ------" },
            { id: 28, question: "What is the primary benefit of stopping an Autonomous Database?", options: [{ id: "A", text: "It permanently deletes the database." }, { id: "B", text: "It pauses compute billing while preserving the database." }, { id: "C", text: "It removes all stored data." }, { id: "D", text: "It disables automatic backups permanently." }], correctAnswer: "B", explanation: "Stopping the database pauses compute (CPU) charges while keeping the database intact. The data remains persistent and can be accessed after restarting." },
            { id: 29, question: "Which charges continue even when an Autonomous Database is stopped?", options: [{ id: "A", text: "CPU charges only." }, { id: "B", text: "Storage charges only." }, { id: "C", text: "Networking charges only." }, { id: "D", text: "No charges are incurred." }], correctAnswer: "B", explanation: "When the database is stopped, compute billing pauses, but storage charges continue because the data is still retained." },
            { id: 30, question: "What happens to the data when an Autonomous Database is stopped?", options: [{ id: "A", text: "It is permanently deleted." }, { id: "B", text: "It is backed up and removed from storage." }, { id: "C", text: "It remains persistent and becomes available again after the database is started." }, { id: "D", text: "It becomes read-only permanently." }], correctAnswer: "C", explanation: "Stopping only pauses the database instance; it does not affect the stored data. Once restarted, all data is available as before." },
            { id: 31, question: "Which lifecycle state indicates that the database is in the process of starting?", options: [{ id: "A", text: "Available" }, { id: "B", text: "Starting" }, { id: "C", text: "Provisioning" }, { id: "D", text: "Scaling" }], correctAnswer: "B", explanation: "During startup, the lifecycle state changes to Starting. After startup completes, it changes to Available." },
            { id: 32, question: "What does the \"Available\" lifecycle state indicate?", options: [{ id: "A", text: "The database is being backed up." }, { id: "B", text: "The database is ready to accept user sessions and workloads." }, { id: "C", text: "The database is stopped." }, { id: "D", text: "The database is waiting for scaling." }], correctAnswer: "B", explanation: "The Available state means the database is fully operational. Users and applications can connect and perform workloads." },
            { id: 33, question: "Why might an organization configure an Auto Start/Stop schedule?", options: [{ id: "A", text: "To increase storage automatically." }, { id: "B", text: "To reduce costs by stopping the database during periods of inactivity." }, { id: "C", text: "To improve database security." }, { id: "D", text: "To automatically create backups every hour." }], correctAnswer: "B", explanation: "Scheduling start and stop times helps reduce compute costs by ensuring the database runs only when needed." },
            { id: 34, question: "Which statement about Auto Start/Stop schedules is correct?", options: [{ id: "A", text: "Both start and stop times must always be configured." }, { id: "B", text: "Only stop times are supported." }, { id: "C", text: "You can configure only a start time, only a stop time, or both." }, { id: "D", text: "Schedules can only be configured once." }], correctAnswer: "C", explanation: "Oracle provides flexibility by allowing either start times, stop times, or both depending on operational requirements." },
            { id: 35, question: "What time standard is used when configuring Auto Start/Stop schedules?", options: [{ id: "A", text: "Local system time." }, { id: "B", text: "Pacific Standard Time (PST)." }, { id: "C", text: "Coordinated Universal Time (UTC)." }, { id: "D", text: "Greenwich Mean Time (GMT+1)." }], correctAnswer: "C", explanation: "Scheduled start and stop times are specified using Coordinated Universal Time (UTC) for consistency across regions." },
            { id: 36, question: "Besides using the OCI Console, how can administrators start or stop an Autonomous Database?", options: [{ id: "A", text: "Only through SQL commands." }, { id: "B", text: "Using REST APIs for automation and scripting." }, { id: "C", text: "Only through SSH access." }, { id: "D", text: "Using Oracle SQL Developer exclusively." }], correctAnswer: "B", explanation: "Oracle supports REST APIs, allowing administrators to automate database start and stop operations through scripts or applications." },
            { id: 37, question: "Which statement best summarizes the start/stop capability of Autonomous Database?", options: [{ id: "A", text: "Starting and stopping requires database recreation." }, { id: "B", text: "The feature provides a simple way to manage availability while optimizing compute costs." }, { id: "C", text: "Stopping permanently disables the database." }, { id: "D", text: "Starting the database requires manual restoration from backup." }], correctAnswer: "B", explanation: "The start/stop feature enables organizations to reduce compute costs without affecting stored data, while allowing the database to be quickly made available when needed. ----" },
            { id: 38, question: "Which user account is automatically created when an Autonomous Database is provisioned?", options: [{ id: "A", text: "SYSTEM" }, { id: "B", text: "SYS" }, { id: "C", text: "ADMIN" }, { id: "D", text: "ROOT" }], correctAnswer: "C", explanation: "The ADMIN user is automatically created during database provisioning. The administrator sets its password as part of the provisioning process." },
            { id: 39, question: "Why should additional users be created after provisioning an Autonomous Database?", options: [{ id: "A", text: "The ADMIN account cannot access the database." }, { id: "B", text: "To provide separate accounts for applications, developers, and end users." }, { id: "C", text: "To increase database storage." }, { id: "D", text: "To enable automatic backups." }], correctAnswer: "B", explanation: "Separate user accounts improve security and access management. Applications and users should not share the ADMIN account for everyday operations." },
            { id: 40, question: "What is the primary purpose of the DWROLE role?", options: [{ id: "A", text: "To manage database backups." }, { id: "B", text: "To provide common privileges required by developers and data warehouse users." }, { id: "C", text: "To administer Oracle Cloud Infrastructure." }, { id: "D", text: "To configure database networking." }], correctAnswer: "B", explanation: "DWROLE bundles the basic privileges needed by developers, analysts, and data warehouse users, simplifying user management." },
            { id: 41, question: "Which task is NOT required when creating a new user in Autonomous Database?", options: [{ id: "A", text: "Specifying a username." }, { id: "B", text: "Providing a password." }, { id: "C", text: "Assigning a role such as DWROLE." }, { id: "D", text: "Configuring default and temporary tablespaces." }], correctAnswer: "D", explanation: "Autonomous Database automatically manages tablespaces, so administrators do not need to configure them when creating users." },
            { id: 42, question: "If a SQL client is unavailable, which Oracle tool can be used to create and manage users?", options: [{ id: "A", text: "Oracle VM Manager." }, { id: "B", text: "Database Actions (SQL Developer Web)." }, { id: "C", text: "Oracle Enterprise Manager only." }, { id: "D", text: "Oracle Linux Terminal." }], correctAnswer: "B", explanation: "Database Actions provides a browser-based interface for managing users and performing database administration tasks without a local SQL client." },
            { id: 43, question: "How can the ADMIN password be changed through the OCI Console?", options: [{ id: "A", text: "By recreating the database." }, { id: "B", text: "Through the More Actions menu by selecting Administrator Password." }, { id: "C", text: "By changing the database version." }, { id: "D", text: "By modifying the storage settings." }], correctAnswer: "B", explanation: "The OCI Console includes an option under More Actions to update the ADMIN password without using SQL commands." },
            { id: 44, question: "What is the purpose of the \"Granted\" option when assigning a role to a user?", options: [{ id: "A", text: "It deletes the role." }, { id: "B", text: "It assigns the selected role to the user." }, { id: "C", text: "It changes the user's password." }, { id: "D", text: "It creates a new role." }], correctAnswer: "B", explanation: "Selecting Granted gives the user the specified role and its associated privileges." },
            { id: 45, question: "What does the \"Admin\" option for a granted role allow a user to do?", options: [{ id: "A", text: "Delete the database." }, { id: "B", text: "Grant that role to other users." }, { id: "C", text: "Modify database storage." }, { id: "D", text: "Change the database version." }], correctAnswer: "B", explanation: "The Admin option allows the user to grant the assigned role to other database users." },
            { id: 46, question: "Which additional role is required for users who need to work with the built-in Data Transforms tool?", options: [{ id: "A", text: "DBA" }, { id: "B", text: "CONNECT" }, { id: "C", text: "DATA_TRANSFORMS_USER" }, { id: "D", text: "RESOURCE" }], correctAnswer: "C", explanation: "Users of the built-in Data Transforms feature require the DATA_TRANSFORMS_USER role in addition to their standard privileges." },
            { id: 47, question: "What is the main advantage of using Database Actions for user management?", options: [{ id: "A", text: "It eliminates the need for database passwords." }, { id: "B", text: "It provides a web-based interface to create users, assign roles, and manage accounts." }, { id: "C", text: "It automatically grants DBA privileges." }, { id: "D", text: "It replaces Oracle Cloud Infrastructure." }], correctAnswer: "B", explanation: "Database Actions simplifies administration through a graphical web interface, allowing user and role management without external client tools." },
            { id: 48, question: "What is the primary purpose of an Elastic Pool in Autonomous Database?", options: [{ id: "A", text: "To increase database storage automatically." }, { id: "B", text: "To consolidate Autonomous Databases and optimize compute resource usage." }, { id: "C", text: "To replace Oracle RAC." }, { id: "D", text: "To automate database backups." }], correctAnswer: "B", explanation: "Elastic Pools allow multiple Autonomous Databases to share compute resources efficiently. This improves utilization while reducing operational costs." },
            { id: 49, question: "Why should organizations use Elastic Pools for database consolidation?", options: [{ id: "A", text: "They eliminate the need for backups." }, { id: "B", text: "They reduce administrative complexity and improve resource utilization." }, { id: "C", text: "They require dedicated hardware for every database." }, { id: "D", text: "They prevent databases from scaling." }], correctAnswer: "B", explanation: "Elastic Pools simplify administration by consolidating many databases into a shared resource pool while allowing elastic scaling." },
            { id: 50, question: "What determines both the compute cost and the maximum provisionable ECPUs in an Elastic Pool?", options: [{ id: "A", text: "Database version." }, { id: "B", text: "Pool Size." }, { id: "C", text: "Backup retention policy." }, { id: "D", text: "Number of users." }], correctAnswer: "B", explanation: "The selected Pool Size determines the compute cost and the amount of compute capacity available within the pool." },
            { id: 51, question: "What is a Pool Leader?", options: [{ id: "A", text: "The largest database in the pool." }, { id: "B", text: "The Autonomous Database instance that owns the Elastic Pool." }, { id: "C", text: "A database that performs backups for all pool members." }, { id: "D", text: "A standby database." }], correctAnswer: "B", explanation: "The Pool Leader is the Autonomous Database that owns and manages the Elastic Pool to which other databases belong." },
            { id: 52, question: "What is a Pool Member?", options: [{ id: "A", text: "An Autonomous Database instance that runs within an Elastic Pool." }, { id: "B", text: "A user assigned to manage databases." }, { id: "C", text: "A compute node inside Exadata." }, { id: "D", text: "A backup database." }], correctAnswer: "A", explanation: "A Pool Member is simply an Autonomous Database that shares compute resources within an Elastic Pool." },
            { id: 53, question: "What is the relationship between Pool Capacity and Pool Shape?", options: [{ id: "A", text: "Pool Capacity is equal to the Pool Shape." }, { id: "B", text: "Pool Capacity is twice the Pool Shape." }, { id: "C", text: "Pool Capacity is four times the Pool Shape." }, { id: "D", text: "Pool Capacity is unlimited." }], correctAnswer: "C", explanation: "Oracle defines the maximum pool capacity as 4 × the selected Pool Shape, allowing databases to burst beyond the purchased baseline." },
            { id: 54, question: "How does an Elastic Pool improve cost efficiency?", options: [{ id: "A", text: "By allocating one dedicated ECPU to every database." }, { id: "B", text: "By allowing databases to share compute resources instead of reserving dedicated compute." }, { id: "C", text: "By disabling Auto Scaling." }, { id: "D", text: "By eliminating storage costs." }], correctAnswer: "B", explanation: "Since databases rarely use peak compute simultaneously, shared resources significantly improve utilization and lower costs." },
            { id: 55, question: "According to Oracle, what level of cost savings can Elastic Pools provide?", options: [{ id: "A", text: "Up to 2×." }, { id: "B", text: "Up to 4×." }, { id: "C", text: "Up to 8×." }, { id: "D", text: "Unlimited." }], correctAnswer: "C", explanation: "Oracle states that Elastic Pools can provide up to 8× cost savings, depending on workload consolidation patterns." },
            { id: 56, question: "Why are Elastic Pools especially beneficial for infrequently used databases?", options: [{ id: "A", text: "They permanently disable unused databases." }, { id: "B", text: "They allow many lightly used databases to share the same compute resources efficiently." }, { id: "C", text: "They increase storage capacity automatically." }, { id: "D", text: "They require no licensing." }], correctAnswer: "B", explanation: "Databases with low or intermittent workloads don't need dedicated compute, making shared pools highly cost-effective." },
            { id: 57, question: "Which statement best describes the Elastic Pool pricing model?", options: [{ id: "A", text: "Every database requires dedicated ECPUs." }, { id: "B", text: "Customers purchase a baseline pool of ECPUs, and databases share those resources while scaling as" }, { id: "C", text: "Pricing depends only on storage usage." }, { id: "D", text: "Each database is billed independently regardless of pooling." }], correctAnswer: "B", explanation: "Customers buy a baseline compute capacity, and all databases in the pool share it. This enables efficient consolidation and elastic scaling." },
            { id: 58, question: "Which of the following is NOT a supported method for creating a new Autonomous Database as a clone of an existing one?", options: [{ id: "A", text: "As a full copy" }, { id: "B", text: "Containing just the metadata of the source" }, { id: "C", text: "As a refreshable clone" }, { id: "D", text: "As a cross-cloud provider clone" }], correctAnswer: "D", explanation: "Cross-cloud provider cloning is not a supported feature in this context. The supported methods for creating an Autonomous Database clone are as a full copy, containing just the metadata of the source, or as a refreshable clone." },
            { id: 59, question: "For how many consecutive days can a refreshable clone trail the source database before it can no longer be refreshed?", options: [{ id: "A", text: "3 days" }, { id: "B", text: "7 days" }, { id: "C", text: "14 days" }, { id: "D", text: "30 days" }], correctAnswer: "B", explanation: "Refreshable clones have a strict technical limitation where they can only trail the source database for a maximum period of 7 consecutive days." },
            { id: 60, question: "What happens to a refreshable clone if it has not been refreshed and exceeds the time limit?", options: [{ id: "A", text: "It is automatically deleted." }, { id: "B", text: "It is automatically converted into a full standalone copy." }, { id: "C", text: "The instance becomes a read-only database." }, { id: "D", text: "It is disconnected from the source and upgraded to a newer version." }], correctAnswer: "C", explanation: "Once the 7-day refresh time limit is exceeded, the continuous update mechanism is halted, and the instance permanently transitions into a read-only database state." },
            { id: 61, question: "What might cause the disconnection of a refreshable clone from its source database to fail?", options: [{ id: "A", text: "If the source database is currently running a backup." }, { id: "B", text: "If the source database has scaled down its storage, and the clone has a larger amount of data than the" }, { id: "C", text: "If the clone was created from a backup instead of a live instance." }, { id: "D", text: "If the network latency between the source and clone regions exceeds 50 ms." }], correctAnswer: "B", explanation: "Disconnecting a refreshable clone can fail due to a storage mismatch. This occurs when the source database has scaled down its storage while the clone still contains more data." },
            { id: 62, question: "When creating an Autonomous Database clone, which of the following is true regarding its workload type?", options: [{ id: "A", text: "The clone must strictly maintain the same workload type as the source database." }, { id: "B", text: "By default, the clone is of the same workload type, but you can optionally select a different one." }, { id: "C", text: "By default, the clone forces you to choose a new workload type." }, { id: "D", text: "Cloning to a different workload type is only possible if you are cloning from a backup." }], correctAnswer: "B", explanation: "By default, the clone inherits the workload type of the source database. However, administrators can choose a different workload type during the cloning process." },
            { id: 63, question: "How can an Autonomous Database be configured to use Private endpoints if the source uses Public endpoints?", options: [{ id: "A", text: "By changing the endpoint settings directly on the source database before cloning." }, { id: "B", text: "By cloning from an existing Autonomous Database with Public endpoints." }, { id: "C", text: "Private endpoints cannot be configured if the source database uses Public endpoints." }, { id: "D", text: "By contacting Oracle Support to migrate the network configuration." }], correctAnswer: "B", explanation: "During cloning, you can configure the cloned Autonomous Database to use Private endpoints, even if the source database uses Public endpoints." },
            { id: 64, question: "If disconnecting a refreshable clone fails because the source database has scaled down its storage, what is one of the recommended solutions?", options: [{ id: "A", text: "Delete the clone and create a standard full copy instead." }, { id: "B", text: "Manually delete data in the refreshable clone to match the source's new storage size." }, { id: "C", text: "Scale up the storage on the source database temporarily before disconnecting." }, { id: "D", text: "Change the workload type of the refreshable clone to free up storage space." }], correctAnswer: "C", explanation: "Temporarily increasing the source database storage resolves the storage mismatch. After disconnecting the clone, the source storage can be reduced again." },
            { id: 65, question: "Which of the following is NOT explicitly mentioned in the transcript as a use case for taking a copy or cloning an Autonomous Database?", options: [{ id: "A", text: "Providing the same environment for a development environment." }, { id: "B", text: "Testing out upgrades or code changes." }, { id: "C", text: "Creating a copy in a different region for different application access." }, { id: "D", text: "Selling the database snapshot on the Oracle Cloud Marketplace." }], correctAnswer: "D", explanation: "Common cloning use cases include development, testing, and cross-region deployment. Selling database snapshots on Oracle Cloud Marketplace is not mentioned as a supported use case." },
            { id: 66, question: "What action is required if you want to use a refreshable clone that has exceeded the 7-day limit as a regular, fully functioning database?", options: [{ id: "A", text: "You must disconnect the clone from the source database and use it as a standalone database." }, { id: "B", text: "You must pay a penalty fee to unlock the refresh capability." }, { id: "C", text: "You must restore the source database from a backup prior to the 7-day limit." }, { id: "D", text: "It is impossible; you must delete the read-only instance and start over." }], correctAnswer: "A", explanation: "Disconnecting the refreshable clone converts it into a standalone read-write database, allowing it to function independently of the source." },
            { id: 67, question: "When creating a clone, what states can the source database be in?", options: [{ id: "A", text: "It must be completely shut down to ensure data consistency." }, { id: "B", text: "It can only be cloned from a previous nightly backup." }, { id: "C", text: "It can be a live running database instance or a backup of the source." }, { id: "D", text: "It can only be a read-only instance." }], correctAnswer: "C", explanation: "Oracle supports cloning from both a live running Autonomous Database and an existing backup, providing flexibility for different use cases." },
            { id: 68, question: "Why would you move an Autonomous Database to another compartment?", options: [{ id: "A", text: "To reduce storage usage" }, { id: "B", text: "To access different business applications or network resources" }, { id: "C", text: "To delete backups" }, { id: "D", text: "To disable autoscaling" }], correctAnswer: "B", explanation: "Moving an Autonomous Database to another compartment allows it to inherit different IAM policies and access different business applications or network resources." },
            { id: 69, question: "When an Autonomous Database is moved to another compartment, what happens to its automatic backups?", options: [{ id: "A", text: "They are deleted." }, { id: "B", text: "They remain in the old compartment." }, { id: "C", text: "They are moved with the database." }, { id: "D", text: "They must be recreated manually." }], correctAnswer: "C", explanation: "Automatic backups move together with the Autonomous Database. No manual backup migration or reconfiguration is required." },
            { id: 70, question: "Before moving an Autonomous Database, you must have:", options: [{ id: "A", text: "SYSDBA privileges only" }, { id: "B", text: "Administrator password" }, { id: "C", text: "Appropriate permissions in both source and target compartments" }, { id: "D", text: "Object Storage access only" }], correctAnswer: "C", explanation: "The user performing the move must have the necessary IAM permissions for both the source and destination compartments." },
            { id: 71, question: "After moving an Autonomous Database to a new compartment, which policies apply?", options: [{ id: "A", text: "Policies from the old compartment only" }, { id: "B", text: "Policies from both compartments" }, { id: "C", text: "Policies defined in the new compartment" }, { id: "D", text: "No policies apply" }], correctAnswer: "C", explanation: "Once the move is complete, the database is governed by the IAM policies associated with the new compartment." },
            { id: 72, question: "Which menu option is used to move an Autonomous Database?", options: [{ id: "A", text: "Scale Database" }, { id: "B", text: "Clone Database" }, { id: "C", text: "Move Resource" }, { id: "D", text: "Export Database" }], correctAnswer: "C", explanation: "Oracle Cloud provides the Move Resource option to transfer an Autonomous Database between compartments." },
            { id: 73, question: "How can you monitor the progress of moving an Autonomous Database?", options: [{ id: "A", text: "Metrics" }, { id: "B", text: "Audit Logs" }, { id: "C", text: "Work Requests" }, { id: "D", text: "Performance Hub" }], correctAnswer: "C", explanation: "Oracle tracks long-running operations such as moving resources through the Work Requests page, where progress and status can be monitored." },
            { id: 74, question: "After the move operation completes, the Autonomous Database becomes:", options: [{ id: "A", text: "Deleted" }, { id: "B", text: "Available in the new compartment" }, { id: "C", text: "Read-only" }, { id: "D", text: "Stopped" }], correctAnswer: "B", explanation: "After a successful move, the database becomes available in the destination compartment and continues normal operation." },
            { id: 75, question: "Which statement about moving an Autonomous Database is TRUE?", options: [{ id: "A", text: "It requires creating a new database." }, { id: "B", text: "Automatic backups are moved along with the database." }, { id: "C", text: "The database must be restored from backup." }, { id: "D", text: "Users must manually copy all data." }], correctAnswer: "B", explanation: "Moving the database is a resource management operation. Oracle automatically moves associated backups without requiring manual intervention." },
            { id: 76, question: "Which of the following may be a business reason for moving an Autonomous Database?", options: [{ id: "A", text: "To change the compartment for different subnet access" }, { id: "B", text: "To increase CPU automatically" }, { id: "C", text: "To enable Data Guard" }, { id: "D", text: "To create a manual backup" }], correctAnswer: "A", explanation: "Organizations may move databases to compartments that have different networking configurations, security policies, or subnet access." },
            { id: 77, question: "Which statement is FALSE regarding moving an Autonomous Database?", options: [{ id: "A", text: "Appropriate privileges are required." }, { id: "B", text: "Automatic backups move with the database." }, { id: "C", text: "New compartment policies are applied after the move." }, { id: "D", text: "The database must be recreated manually after moving." }], correctAnswer: "D", explanation: "Moving an Autonomous Database does not require recreating it. The existing database is simply transferred to the new compartment with its associated resources." },
            { id: 78, question: "What is the main purpose of events?", options: [{ id: "A", text: "To store database backups" }, { id: "B", text: "To provide notifications like password expiry and service status changes" }, { id: "C", text: "To increase database performance" }, { id: "D", text: "To encrypt database traffic" }], correctAnswer: "B", explanation: "OCI Events capture important changes in Oracle Cloud resources, such as password expiry or service status updates. These events can automatically trigger notifications or other actions." },
            { id: 79, question: "Which OCI service is used for broadcasting messages in a publish-subscribe model?", options: [{ id: "A", text: "Compute Service" }, { id: "B", text: "Storage Service" }, { id: "C", text: "Notification Service" }, { id: "D", text: "Logging Service" }], correctAnswer: "C", explanation: "OCI Notification Service delivers messages using the publish-subscribe model. It allows one message to be sent to multiple subscribers." },
            { id: 80, question: "What is a \"topic\" in OCI Notifications?", options: [{ id: "A", text: "A database table" }, { id: "B", text: "A communication channel for sending messages to subscribers" }, { id: "C", text: "A CPU monitoring tool" }, { id: "D", text: "A backup system" }], correctAnswer: "B", explanation: "A topic acts as a communication channel that receives published messages. All subscribed users or services receive notifications from that topic." },
            { id: 81, question: "What must be created after creating a topic to receive notifications?", options: [{ id: "A", text: "Alarm rule" }, { id: "B", text: "Subscription" }, { id: "C", text: "Compartment" }, { id: "D", text: "Metric stream" }], correctAnswer: "B", explanation: "A subscription links a recipient to a notification topic. Without a subscription, notifications cannot be delivered." },
            { id: 82, question: "In Oracle Autonomous Database Serverless, which notification methods can be used when an alarm is triggered? (Select all that apply)", options: [{ id: "A", text: "Email via OCI Notification Service" }, { id: "B", text: "HTTPS webhook via OCI Notification Service" }, { id: "C", text: "Slack integration via OCI Notifications" }, { id: "D", text: "Direct FTP transfer from database" }, { id: "E", text: "PagerDuty integration via OCI Notifications" }], correctAnswer: "ABCE", explanation: "OCI Notification Service supports multiple notification protocols, including Email, HTTPS, Slack, and PagerDuty. FTP is not supported as a notification method." },
            { id: 83, question: "Why does a subscription show \"Pending\" status initially?", options: [{ id: "A", text: "Database is restarting" }, { id: "B", text: "Email confirmation is required from the recipient" }, { id: "C", text: "Alarm is not created" }, { id: "D", text: "Topic is deleted" }], correctAnswer: "B", explanation: "Email subscriptions remain in the Pending state until the recipient confirms the subscription. Notifications are sent only after confirmation." },
            { id: 84, question: "Where can you create an alarm for an Oracle Autonomous Database metric (such as CPU utilization)?", options: [{ id: "A", text: "IAM Console" }, { id: "B", text: "Metrics section of the Autonomous Database in OCI Console" }, { id: "C", text: "Object Storage bucket" }, { id: "D", text: "Compute instance dashboard" }], correctAnswer: "B", explanation: "OCI allows alarms to be created directly from the Metrics page of an Autonomous Database. This simplifies monitoring database performance metrics." },
            { id: 85, question: "Which metric was used to create the alarm?", options: [{ id: "A", text: "Memory Usage" }, { id: "B", text: "Storage Utilization" }, { id: "C", text: "CPU Utilization" }, { id: "D", text: "Network Latency" }], correctAnswer: "C", explanation: "CPU Utilization is a commonly monitored metric in Autonomous Database. It helps administrators detect high workload conditions." },
            { id: 86, question: "What condition typically triggers a CPU utilization alarm in Oracle Autonomous Database?", options: [{ id: "A", text: "CPU utilization drops below a defined threshold" }, { id: "B", text: "CPU utilization reaches exactly 100%" }, { id: "C", text: "CPU utilization exceeds a configured threshold value" }, { id: "D", text: "CPU utilization becomes zero" }], correctAnswer: "C", explanation: "OCI Alarms compare monitored metrics with configured threshold values. An alert is generated when CPU usage exceeds the defined limit." },
            { id: 87, question: "What happens when the alarm is triggered?", options: [{ id: "A", text: "Database shuts down" }, { id: "B", text: "Subscribers receive notifications via the topic" }, { id: "C", text: "Metrics are deleted" }, { id: "D", text: "New topic is created automatically" }], correctAnswer: "B", explanation: "When an alarm enters the firing state, it publishes a message to the configured topic. All active subscribers receive the notification." },
            { id: 88, question: "What is the correct role of an Event Rule in OCI?", options: [{ id: "A", text: "It stores CPU metrics permanently" }, { id: "B", text: "It defines conditions under which system-generated events trigger actions" }, { id: "C", text: "It replaces alarms for monitoring" }, { id: "D", text: "It sends emails directly to users" }], correctAnswer: "B", explanation: "Event Rules specify which OCI events should trigger an action. They connect system events to services such as Notifications." },
            { id: 89, question: "In OCI architecture, what is the first component that receives an event before notifications are sent to users?", options: [{ id: "A", text: "Alarm" }, { id: "B", text: "Subscription" }, { id: "C", text: "Topic" }, { id: "D", text: "Metric stream" }], correctAnswer: "C", explanation: "When an event occurs, it is published to a Notification Topic. The topic then distributes the message to all subscribed recipients." },
            { id: 90, question: "Which statement best describes the relationship between a Topic and Subscription?", options: [{ id: "A", text: "A topic sends emails directly" }, { id: "B", text: "A subscription generates events" }, { id: "C", text: "A topic is a channel and subscriptions are recipients of messages" }, { id: "D", text: "Subscription replaces alarms" }], correctAnswer: "C", explanation: "A topic acts as the communication channel, while subscriptions specify who receives the published messages." },
            { id: 91, question: "What happens if a subscription is not confirmed by the user?", options: [{ id: "A", text: "It becomes active automatically after 24 hours" }, { id: "B", text: "It can still receive alerts" }, { id: "C", text: "It remains in pending state and cannot receive notifications" }, { id: "D", text: "The topic gets deleted" }], correctAnswer: "C", explanation: "Until the recipient confirms the subscription, it remains in the Pending state. OCI does not send notifications to unconfirmed subscriptions." },
            { id: 92, question: "Which OCI component is specifically responsible for evaluating CPU utilization thresholds?", options: [{ id: "A", text: "Event Rule" }, { id: "B", text: "Alarm" }, { id: "C", text: "Topic" }, { id: "D", text: "Subscription" }], correctAnswer: "B", explanation: "OCI Alarms continuously evaluate monitored metrics against configured thresholds. When the threshold is exceeded, the alarm is triggered." },
            { id: 93, question: "What is the default backup retention period for an Oracle Autonomous Database?", options: [{ id: "A", text: "30 days" }, { id: "B", text: "45 days" }, { id: "C", text: "60 days" }, { id: "D", text: "90 days" }], correctAnswer: "C", explanation: "Autonomous Database automatically retains backups for 60 days. During this period, you can restore the database to any point in time." },
            { id: 94, question: "What is the primary benefit of Point-in-Time Recovery (PITR)?", options: [{ id: "A", text: "It restores only database users." }, { id: "B", text: "It restores the database to a specific point within the backup retention period." }, { id: "C", text: "It restores only manual backups." }, { id: "D", text: "It permanently increases backup retention." }], correctAnswer: "B", explanation: "Point-in-Time Recovery allows the database to be restored to a user-specified time within the retention period. Oracle automatically selects the appropriate backup for recovery." },
            { id: 95, question: "Which statement about manual backups is correct?", options: [{ id: "A", text: "Manual backups replace automatic backups." }, { id: "B", text: "Manual backups are stored in OCI Object Storage." }, { id: "C", text: "Manual backups are stored only inside the database." }, { id: "D", text: "Manual backups require disabling automatic backups." }], correctAnswer: "B", explanation: "Manual backups are stored in an Oracle Cloud Infrastructure Object Storage bucket. They are commonly taken before major database changes." },
            { id: 96, question: "Which methods can be used to initiate database recovery?", options: [{ id: "A", text: "SQL*Plus only." }, { id: "B", text: "Cloud Console or API." }, { id: "C", text: "Object Storage Console only." }, { id: "D", text: "OCI CLI only." }], correctAnswer: "B", explanation: "Oracle allows recovery to be initiated through either the OCI Cloud Console or REST APIs for automated operations." },
            { id: 97, question: "During a restore operation, what lifecycle state is displayed for the database?", options: [{ id: "A", text: "Available" }, { id: "B", text: "Starting" }, { id: "C", text: "Restore in Progress" }, { id: "D", text: "Scaling" }], correctAnswer: "C", explanation: "While recovery is running, the database lifecycle state changes to Restore in Progress. Once complete, it returns to Available." },
            { id: 98, question: "How can administrators monitor the progress of a restore operation?", options: [{ id: "A", text: "Through SQL queries only." }, { id: "B", text: "Using Work Requests in the OCI Console." }, { id: "C", text: "Using Object Storage logs." }, { id: "D", text: "Using IAM policies." }], correctAnswer: "B", explanation: "OCI Work Requests display the current status and progress of long-running operations such as restore and recovery." },
            { id: 99, question: "After a successful restore, what is the state of the Autonomous Database?", options: [{ id: "A", text: "Read-only." }, { id: "B", text: "Stopped." }, { id: "C", text: "Available and Open for Read-Write." }, { id: "D", text: "Backup mode." }], correctAnswer: "C", explanation: "Once recovery finishes successfully, the database becomes available and immediately opens for normal read-write operations." },
            { id: 100, question: "Which requirement must be met before manual backups can be created?", options: [{ id: "A", text: "Automatic backups must be disabled." }, { id: "B", text: "OCI Object Storage credentials and a backup bucket must be configured." }, { id: "C", text: "Data Guard must be enabled." }, { id: "D", text: "Auto Scaling must be disabled." }], correctAnswer: "B", explanation: "Manual backups require an Object Storage bucket and valid OCI credentials. These are configured only once before taking backups." },
            { id: 101, question: "Which naming convention is required for the Object Storage bucket used for manual backups?", options: [{ id: "A", text: "Any bucket name is acceptable." }, { id: "B", text: "backup_displayname in uppercase." }, { id: "C", text: "backup_databasename using the actual database name in lowercase." }, { id: "D", text: "database_backup with mixed case." }], correctAnswer: "C", explanation: "Oracle requires the bucket name format backup_databasename using the actual database name (not the display name) and all lowercase letters." },
            { id: 102, question: "Which statement about Long-Term Backups is correct?", options: [{ id: "A", text: "They support only one-time backups." }, { id: "B", text: "They can be scheduled weekly, monthly, or annually with retention from 3 months to 10 years." }, { id: "C", text: "Their maximum retention period is 60 days." }, { id: "D", text: "They are stored only in local database storage." }], correctAnswer: "B", explanation: "Long-Term Backups support one-time or scheduled backups. Retention can be configured from 3 months up to 10 years." },
            { id: 103, question: "What property is configured to specify the default Object Storage bucket for manual backups?", options: [{ id: "A", text: "DEFAULT_STORAGE_BUCKET" }, { id: "B", text: "DEFAULT_BACKUP_BUCKET" }, { id: "C", text: "BACKUP_STORAGE_LOCATION" }, { id: "D", text: "OCI_BACKUP_PATH" }], correctAnswer: "B", explanation: "The DEFAULT_BACKUP_BUCKET property identifies the Object Storage bucket where manual backups are stored." },
            { id: 104, question: "Why must a database credential be created before taking manual backups?", options: [{ id: "A", text: "To increase backup speed." }, { id: "B", text: "To authenticate access to the OCI Object Storage bucket." }, { id: "C", text: "To enable Auto Scaling." }, { id: "D", text: "To encrypt the backup." }], correctAnswer: "B", explanation: "The database credential securely authenticates the database when writing manual backups to OCI Object Storage." },
            { id: 105, question: "What is the primary purpose of Autonomous Data Guard in an Autonomous Database environment?", options: [{ id: "A", text: "To increase database storage capacity." }, { id: "B", text: "To provide automatic database failover and high availability." }, { id: "C", text: "To optimize SQL query execution." }, { id: "D", text: "To automate user creation." }], correctAnswer: "B", explanation: "Autonomous Data Guard continuously protects the primary database by maintaining a synchronized standby. If the primary fails, the standby automatically takes over to ensure high availability." },
            { id: 106, question: "During an automatic failover, which statement is correct?", options: [{ id: "A", text: "The user must manually configure a new database connection." }, { id: "B", text: "New wallets and connection URLs must be downloaded." }, { id: "C", text: "The standby database automatically becomes the primary while existing wallets and URLs continue to" }, { id: "D", text: "The database must be restored from backup before users can reconnect." }], correctAnswer: "C", explanation: "Oracle preserves the same connection URLs and wallets during failover. Applications reconnect seamlessly without requiring any configuration changes." },
            { id: 107, question: "What happens immediately after a successful failover?", options: [{ id: "A", text: "The original primary database is automatically deleted." }, { id: "B", text: "A new standby database is automatically provisioned for the new primary." }, { id: "C", text: "The administrator must manually create another standby database." }, { id: "D", text: "The database enters read-only mode until synchronization completes." }], correctAnswer: "B", explanation: "Once the standby becomes the new primary, Oracle automatically provisions another standby. This ensures continuous disaster recovery protection." },
            { id: 108, question: "How does Oracle improve resilience for a local standby database?", options: [{ id: "A", text: "By placing the standby on the same physical server as the primary." }, { id: "B", text: "By provisioning the standby in a different Availability Domain when possible, or on a different physical" }, { id: "C", text: "By creating multiple copies in the same storage volume." }, { id: "D", text: "By storing backups in Object Storage only." }], correctAnswer: "B", explanation: "Separating the primary and standby reduces the risk of both being affected by the same infrastructure failure. This improves overall fault tolerance." },
            { id: 109, question: "Which statement best describes the difference between a switchover and a failover?", options: [{ id: "A", text: "Switchover is planned, while failover is used during disaster situations." }, { id: "B", text: "Switchover always results in data loss, while failover does not." }, { id: "C", text: "Switchover requires backups, whereas failover does not." }, { id: "D", text: "Both operations are identical except for the interface." }], correctAnswer: "A", explanation: "A switchover is a planned role reversal with no disaster involved. A failover is performed when the primary database becomes unavailable." },
            { id: 110, question: "Under what condition will Oracle Autonomous Database perform an automatic failover?", options: [{ id: "A", text: "Whenever the user clicks the Failover button." }, { id: "B", text: "Only if the primary database becomes unavailable and failover can occur without data loss." }, { id: "C", text: "Whenever CPU utilization exceeds 80%." }, { id: "D", text: "Only after restoring the latest backup." }], correctAnswer: "B", explanation: "Automatic failover occurs only when Oracle can safely promote the standby without losing data. This ensures zero data loss whenever possible." },
            { id: 111, question: "Why should manual failover be considered only during a true disaster scenario?", options: [{ id: "A", text: "Because it permanently disables Autonomous Data Guard." }, { id: "B", text: "Because it may involve a small amount of data loss while prioritizing database availability." }, { id: "C", text: "Because it requires creating a new Autonomous Database." }, { id: "D", text: "Because it cannot be performed from the OCI Console." }], correctAnswer: "B", explanation: "Manual failover is used when automatic failover cannot complete successfully. It prioritizes restoring service quickly, even if a few minutes of data may be lost." },
            { id: 112, question: "Which Recovery Time Objective (RTO) and Recovery Point Objective (RPO) combination is associated with automatic failover?", options: [{ id: "A", text: "RTO: 5 minutes, RPO: 2 minutes." }, { id: "B", text: "RTO: 2 minutes, RPO: 0 minutes." }, { id: "C", text: "RTO: 0 minutes, RPO: 2 minutes." }, { id: "D", text: "RTO: 10 minutes, RPO: 5 minutes." }], correctAnswer: "B", explanation: "Oracle targets a recovery within about two minutes while ensuring zero data loss. This provides both rapid recovery and maximum data protection." },
            { id: 113, question: "What is the primary benefit of configuring a cross-region standby database?", options: [{ id: "A", text: "Faster SQL query execution." }, { id: "B", text: "Increased storage capacity." }, { id: "C", text: "Protection against regional outages." }, { id: "D", text: "Automatic schema upgrades." }], correctAnswer: "C", explanation: "A cross-region standby keeps a synchronized copy in another Oracle Cloud region. If an entire region becomes unavailable, the standby can maintain business continuity." },
            { id: 114, question: "Which statement accurately describes Autonomous Data Guard peer database support?", options: [{ id: "A", text: "Only one local standby database is supported." }, { id: "B", text: "Only one remote standby database is supported." }, { id: "C", text: "Oracle supports one local (same-region) standby and one remote (cross-region) standby database." }, { id: "D", text: "Unlimited standby databases can be created in any region." }], correctAnswer: "C", explanation: "Autonomous Data Guard supports one local standby for high availability and one cross-region standby for disaster recovery. This provides protection against both local and regional failures. This is the whole pdf content <ADDITIONAL_METADATA> The current local time is: 2026-07-04T12:56:32+05:30. The user's current state is as follows: Active Document: c:\Users\HP\Desktop\Stream Training\oci-quiz\src\App.tsx (LANGUAGE_TSX) C <truncated 253 bytes> NOTE: The output was truncated because it was too long. Use a more targeted query or a smaller range to get the information you need." }
          ]
        }